import { Component, Prop, h, Element, State, Host, Listen } from '@stencil/core';
import { getContainerWrapper, getNumberClass } from './notification-indicator-utils';
import { generateRandId } from '../../utils/utils';
import { KEYBOARD_KEYS } from '../../models/keycodes.model';
import {
  NotificationSizes,
  NotificationTypes,
  NotificationsA11yAriaLive,
  NotificationsA11yAriaRole
} from './wdpr-notification.model';

@Component({
  tag: 'wdpr-notification-indicator',
  shadow: true
})
export class WdprNotificationIndicator {
  @Element() el: HTMLWdprNotificationIndicatorElement;

  @State() _internalId: string;

  @Prop() componentId?: string = null;

  @Prop() size: NotificationSizes = "small";
  @Prop() type: NotificationTypes = "alert";
  @Prop() number: number = 0;
  @Prop() decorative: boolean = false;

  @Prop({ attribute: 'a11y-aria-live' }) a11yAriaLive?: NotificationsA11yAriaLive = 'polite';
  @Prop({ attribute: 'a11y-aria-role' }) a11yAriaRole?: NotificationsA11yAriaRole = 'status';
  @Prop({ attribute: 'a11y-label' }) a11yLabel?: string = '';

  componentWillLoad() {
    this._internalId = this.componentId || `wdpr-notification-indicator-${generateRandId()}`;
  }

  @Listen('keydown')
  handleKeyDown(ev: KeyboardEvent) {
    if (ev.key == KEYBOARD_KEYS.ESCAPE) {
      ev.preventDefault();
      (document.activeElement as HTMLElement)?.blur();
    }
  }

  private get _containerWrapper() {
    return getContainerWrapper(this.type, this.size);
  }

  private get _numberClass() {
    return getNumberClass(this.type);
  }

  render() {
    return (
      <Host>
        <div
          id={this._internalId}
          class={this._containerWrapper}
          role={this.a11yAriaRole || undefined}
          aria-live={this.a11yAriaLive || undefined}
          aria-label={this.a11yLabel || undefined}
        >
          <span class={this._numberClass}>
            {this.size === 'small' ? (this.number || '\u200B') : null}
          </span>
        </div>
      </Host>
    );
  }
}
